    gap := N DIV 2;
    WHILE gap > 0 DO
        swapNeeded := FALSE;
        FOR i := gap + 1 TO N DO
            temp := sorted_arr[i];
            j := i;
            WHILE (j > gap) DO
                IF isAscending THEN
                    IF sorted_arr[j - gap] > temp THEN
                        sorted_arr[j] := sorted_arr[j - gap];
                        sorted_arr[j - gap] := temp;
                        swapNeeded := TRUE;
                    END_IF;
                ELSE
                    IF sorted_arr[j - gap] < temp THEN
                        sorted_arr[j] := sorted_arr[j - gap];
                        sorted_arr[j - gap] := temp;
                        swapNeeded := TRUE;
                    END_IF;
