FUNCTION_BLOCK FloatingAverage
VAR_INPUT
    cyclicExecution : BOOL;
    trigger : BOOL;
    value : REAL;
    windowSize : INT;
    reset : BOOL;
END_VAR
VAR_OUTPUT
    average : REAL;
    windowSizeReached : BOOL;
    error : BOOL;
    status : WORD;
END_VAR
VAR
    dataBuffer : ARRAY[1..100] OF REAL;
    bufferIndex : INT := 1;
    sum : REAL := 0.0;
    prevTrigger : BOOL := FALSE;
    validCount : INT := 0;
END_VAR

BEGIN
    status := 16#0000;
    error := FALSE;
    average := 0.0;
    windowSizeReached := FALSE;

    IF windowSize < 1 OR windowSize > 100 THEN
        error := TRUE;
        status := 16#8200;
        RETURN;
    END_IF;

    IF reset THEN
        bufferIndex := 1;
        validCount := 0;
        sum := 0.0;
        FOR i := 1 TO windowSize DO
            dataBuffer[i] := 0.0;
        END_FOR;
    END_IF;

    IF cyclicExecution = TRUE OR (trigger = TRUE AND prevTrigger = FALSE) THEN
        IF validCount < windowSize THEN
            dataBuffer[validCount + 1] := value;
            sum := sum + value;
            validCount := validCount + 1;
        ELSE
            dataBuffer[bufferIndex] := value;
            sum := sum - dataBuffer[bufferIndex] + value;
        END_IF;

        bufferIndex := bufferIndex + 1;
        IF bufferIndex > windowSize THEN
            bufferIndex := 1;
        END_IF;

        IF validCount >= windowSize THEN
            windowSizeReached := TRUE;
            average := sum / windowSize;
        ELSE
            windowSizeReached := FALSE;
            average := sum / validCount;
        END_IF;
    END_IF;

    prevTrigger := trigger;
END_FUNCTION_BLOCK

