IsDaytime := (CurrentTime >= SunriseTime) AND (CurrentTime <= SunsetTime);

IF IsDaytime THEN
    IsHighIntensity := (SolarIntensity >= 90.0);

    IF IsHighIntensity THEN
        IsNoon := TRUE;
    ELSE
        IsMorning := (CurrentTime < NoonTime);
        IsEvening := (CurrentTime >= NoonTime);

        IF IsMorning THEN
            IsNoon := FALSE;
        ELSIF IsEvening THEN
            IsNoon := FALSE;
        END_IF;
    END_IF;

    IF IsNoon THEN
        PanelAngle := NoonAngle;
    ELSIF IsMorning THEN
        PanelAngle := MorningAngle;
    ELSIF IsEvening THEN
        PanelAngle := EveningAngle;
    END_IF;
ELSE
    PanelAngle := 0.0;
END_IF;

IF PanelAngle < 0.0 THEN
