FUNCTION_BLOCK ChargingStationControl
VAR_INPUT
    EVConnected : BOOL;
    EVVoltage : REAL;
    EVCurrent : REAL;
    EVStateOfCharge : REAL;
    ChargingTimer : TIME;
    MinimumVoltage : REAL;
    MaximumCurrent : REAL;
    MinimumSOC : REAL;
    ChargingVoltage : REAL;
    ChargingCurrent : REAL;
    MaximumChargingTime : TIME;
END_VAR
VAR_OUTPUT
    EVCharging : BOOL;
END_VAR
VAR
    StartConditionsMet : BOOL;
    StopConditionsMet : BOOL;
END_VAR
    StartConditionsMet := (EVConnected AND (EVVoltage > MinimumVoltage) AND (EVCurrent <= MaximumCurrent) AND (EVStateOfCharge < 100.0) AND (ChargingTimer <= MaximumChargingTime));
    StopConditionsMet := (NOT EVConnected OR (EVVoltage <= MinimumVoltage) OR (EVCurrent > MaximumCurrent) OR (EVStateOfCharge >= 100.0) OR (ChargingTimer > MaximumChargingTime));
    IF StartConditionsMet AND NOT StopConditionsMet THEN
        EVCharging := TRUE;
    ELSE
        EVCharging := FALSE;
    END_IF;
END_FUNCTION_BLOCK

FUNCTION_BLOCK SmartHVACSystem
VAR_INPUT
    TemperatureSensor : REAL;
    HumiditySensor : REAL;
END_VAR
VAR_OUTPUT
    HVACMode : INT := 0;
    HVACFanSpeed : INT := 0;
END_VAR
VAR
    DesiredTemperature : REAL := 24.0;
    DesiredHumidity : REAL := 50.0;
    TemperatureThreshold : REAL := 1.0;
    HumidityThreshold : REAL := 5.0;
    AdjustedHumidity : REAL;
    AdjustedTemperature : REAL;
    NeedsVentilation : BOOL;
    NeedsHeating : BOOL;
    NeedsCooling : BOOL;
END_VAR
BEGIN
    IF HumiditySensor < 0.0 THEN
        AdjustedHumidity := 0.0;
    ELSIF HumiditySensor > 100.0 THEN
        AdjustedHumidity := 100.0;
    ELSE
        AdjustedHumidity := HumiditySensor;
    END_IF;

    IF TemperatureSensor < -50.0 THEN
        AdjustedTemperature := -50.0;
    ELSIF TemperatureSensor > 100.0 THEN
        AdjustedTemperature := 100.0;
    ELSE
        AdjustedTemperature := TemperatureSensor;
    END_IF;

    IF AdjustedHumidity < (DesiredHumidity - HumidityThreshold) THEN
        NeedsVentilation := TRUE;
    ELSE
        NeedsVentilation := FALSE;
    END_IF;

    IF AdjustedTemperature < (DesiredTemperature - TemperatureThreshold) THEN
        NeedsHeating := TRUE;
    ELSE
        NeedsHeating := FALSE;
    END_IF;

    IF AdjustedTemperature > (DesiredTemperature + TemperatureThreshold) THEN
        NeedsCooling := TRUE;
    ELSE
        NeedsCooling := FALSE;
    END_IF;

    IF NeedsHeating THEN
        HVACMode := 2;
        HVACFanSpeed := 3;
    ELSIF NeedsCooling THEN
        HVACMode := 1;
        HVACFanSpeed := 3;
    ELSIF NeedsVentilation THEN
        HVACMode := 3;
        HVACFanSpeed := 3;
    ELSE
        HVACMode := 0;
        HVACFanSpeed := 0;
    END_IF;
END_FUNCTION_BLOCK

FUNCTION_BLOCK CarParkingSystem
VAR_INPUT
    NewCarSlot : INT;
END_VAR
VAR_OUTPUT
    Elevator1Busy : BOOL;
    Elevator2Busy : BOOL;
    Elevator1Position : INT;
    Elevator2Position : INT;
END_VAR
VAR
    Elevator1Target : INT;
    Elevator2Target : INT;
    CarSlots : ARRAY[1..100] OF BOOL;
    CurrentSlot : INT;
    Elevator1Moving : BOOL;
    Elevator2Moving : BOOL;
    Elevator1Direction : INT;
    Elevator2Direction : INT;
    TaskFound : BOOL;
    SlotRange1 : INT;
    SlotRange2 : INT;
END_VAR

VAR CONSTANT
    TotalSlots : INT := 100;
    Range1Start : INT := 1;
    Range1End : INT := 50;
    Range2Start : INT := 51;
    Range2End : INT := 100;
    InitialPos1 : INT := 1;
    InitialPos2 : INT := 50;
END_VAR

Elevator1Position := InitialPos1;
Elevator2Position := InitialPos2;
Elevator1Target := 0;
Elevator2Target := 0;
Elevator1Moving := FALSE;
Elevator2Moving := FALSE;
TaskFound := FALSE;
CurrentSlot := 1;

IF NewCarSlot >= Range1Start AND NewCarSlot <= Range1End THEN
    Elevator1Target := NewCarSlot;
    Elevator1Busy := TRUE;
    Elevator1Moving := TRUE;
    Elevator1Direction := 0;
    TaskFound := TRUE;
ELSIF NewCarSlot >= Range2Start AND NewCarSlot <= Range2End THEN
    Elevator2Target := NewCarSlot;
    Elevator2Busy := TRUE;
    Elevator2Moving := TRUE;
    Elevator2Direction := 0;
    TaskFound := TRUE;
ELSE
    Elevator1Busy := FALSE;
    Elevator2Busy := FALSE;
    Elevator1Target := 0;
    Elevator2Target := 0;
    TaskFound := FALSE;
END_IF;

IF TaskFound = TRUE THEN
    IF Elevator1Target > Elevator1Position THEN
        Elevator1Direction := 1;
    ELSIF Elevator1Target < Elevator1Position THEN
        Elevator1Direction := -1;
    END_IF;

    IF Elevator2Target > Elevator2Position THEN
        Elevator2Direction := 1;
    ELSIF Elevator2Target < Elevator2Position THEN
        Elevator2Direction := -1;
    END_IF;
END_IF;

IF Elevator1Moving = TRUE AND Elevator1Position <> Elevator1Target THEN
    IF Elevator1Direction = 1 THEN
        Elevator1Position := Elevator1Position + 1;
    ELSIF Elevator1Direction = -1 THEN
        Elevator1Position := Elevator1Position - 1;
    END_IF;
END_IF;

IF Elevator2Moving = TRUE AND Elevator2Position <> Elevator2Target THEN
    IF Elevator2Direction = 1 THEN
        Elevator2Position := Elevator2Position + 1;
    ELSIF Elevator2Direction = -1 THEN
        Elevator2Position := Elevator2Position - 1;
    END_IF;
END_IF;

IF Elevator1Position = Elevator1Target THEN
    Elevator1Moving := FALSE;
    Elevator1Busy := FALSE;
    Elevator1Target := 0;
END_IF;

IF Elevator2Position = Elevator2Target THEN
    Elevator2Moving := FALSE;
    Elevator2Busy := FALSE;
    Elevator2Target := 0;
END_IF;

IF Elevator1Busy = FALSE AND Elevator2Busy = FALSE THEN
    FOR CurrentSlot FROM 1 TO TotalSlots DO
        IF CarSlots[CurrentSlot] = TRUE THEN
            IF CurrentSlot >= Range1Start AND CurrentSlot <= Range1End THEN
                Elevator1Target := CurrentSlot;
                Elevator1Busy := TRUE;
                Elevator1Moving := TRUE;
                Elevator1Direction := 0;
                TaskFound := TRUE;
                EXIT;
            ELSIF CurrentSlot >= Range2Start AND CurrentSlot <= Range2End THEN
                Elevator2Target := CurrentSlot;
                Elevator2Busy := TRUE;
                Elevator2Moving := TRUE;
                Elevator2Direction := 0;
                TaskFound := TRUE;
                EXIT;
            END_IF;
        END_IF;
    END_FOR;
END_IF;

IF TaskFound = TRUE THEN
    IF Elevator1Target > Elevator1Position THEN
        Elevator1Direction := 1;
    ELSIF Elevator1Target < Elevator1Position THEN
        Elevator1Direction := -1;
    END_IF;

    IF Elevator2Target > Elevator2Position THEN
        Elevator2Direction := 1;
    ELSIF Elevator2Target < Elevator2Position THEN
        Elevator2Direction := -1;
    END_IF;
END_IF;

IF Elevator1Moving = TRUE AND Elevator1Position <> Elevator1Target THEN
    IF Elevator1Direction = 1 THEN
        Elevator1Position := Elevator1Position + 1;
    ELSIF Elevator1Direction = -1 THEN
        Elevator1Position := Elevator1Position - 1;
    END_IF;
END_IF;

IF Elevator2Moving = TRUE AND Elevator2Position <> Elevator2Target THEN
    IF Elevator2Direction = 1 THEN
        Elevator2Position := Elevator2Position + 1;
    ELSIF Elevator2Direction = -1 THEN
        Elevator2Position := Elevator2Position - 1;
    END_IF;
END_IF;

IF Elevator1Position = Elevator1Target THEN
    Elevator1Moving := FALSE;
    Elevator1Busy := FALSE;
    Elevator1Target := 0;
END_IF;

IF Elevator2Position = Elevator2Target THEN
    Elevator2Moving := FALSE;
    Elevator2Busy := FALSE;
    Elevator2Target := 0;
END_IF;
END_FUNCTION_BLOCK

