FUNCTION_BLOCK PizzaMakingMachine
VAR_INPUT
    StartButton : BOOL;
    StopButton : BOOL;
    DoughReadySensor : BOOL;
    ToppingsReadySensor : BOOL;
    BakingDoneSensor : BOOL;
END_VAR
VAR_OUTPUT
    DoughRollerMotor : BOOL;
    ToppingDispenser : BOOL;
    ConveyorMotor : BOOL;
    OvenHeater : BOOL;
    OvenTemperature : INT;
END_VAR
VAR
    MachineState : INT;
    StateIdle : INT := 0;
    StateRollingDough : INT := 1;
    StateDispensingToppings : INT := 2;
    StateBaking : INT := 3;
    StateCompleted : INT := 4;
END_VAR
BEGIN
    IF StopButton THEN
        MachineState := StateIdle;
        DoughRollerMotor := FALSE;
        ToppingDispenser := FALSE;
        ConveyorMotor := FALSE;
        OvenHeater := FALSE;
        OvenTemperature := 0;
    ELSIF MachineState = StateIdle THEN
        IF StartButton THEN
            MachineState := StateRollingDough;
        END_IF;
        DoughRollerMotor := FALSE;
        ToppingDispenser := FALSE;
        ConveyorMotor := FALSE;
        OvenHeater := FALSE;
        OvenTemperature := 0;
    ELSIF MachineState = StateRollingDough THEN
        IF NOT DoughReadySensor THEN
            DoughRollerMotor := TRUE;
        ELSE
            MachineState := StateDispensingToppings;
            DoughRollerMotor := FALSE;
            ToppingDispenser := FALSE;
            ConveyorMotor := FALSE;
            OvenHeater := FALSE;
            OvenTemperature := 0;
        END_IF;
    ELSIF MachineState = StateDispensingToppings THEN
        IF NOT ToppingsReadySensor THEN
            ToppingDispenser := TRUE;
        ELSE
            MachineState := StateBaking;
            DoughRollerMotor := FALSE;
            ToppingDispenser := FALSE;
            ConveyorMotor := FALSE;
            OvenHeater := TRUE;
            OvenTemperature := 220;
        END_IF;
    ELSIF MachineState = StateBaking THEN
        IF BakingDoneSensor THEN
            MachineState := StateCompleted;
            DoughRollerMotor := FALSE;
            ToppingDispenser := FALSE;
            ConveyorMotor := TRUE;
            OvenHeater := FALSE;
            OvenTemperature := 0;
        END_IF;
    ELSIF MachineState = StateCompleted THEN
        ConveyorMotor := FALSE;
        OvenHeater := FALSE;
        OvenTemperature := 0;
    END_IF;
END_FUNCTION_BLOCK

