VAR_INPUT
    EntryGateSensor : BOOL;
    ExitGateSensor : BOOL;
    CarDetected : BOOL;
END_VAR
VAR_OUTPUT
    ParkingSpaceNumber : INT := 0;
    RetrievalInProgress : BOOL := FALSE;
END_VAR
VAR
    ParkingSpaces : ARRAY[1..100] OF BOOL;
    i : INT;
    BestSpace : INT;
    SpaceFound : BOOL;
END_VAR

BEGIN
    IF EntryGateSensor THEN
        SpaceFound := FALSE;
        BestSpace := 0;
        FOR i := 1 TO 100 DO
            IF NOT ParkingSpaces[i] AND NOT RetrievalInProgress THEN
                BestSpace := i;
                SpaceFound := TRUE;
                EXIT;
            END_IF;
        END_FOR;

        IF SpaceFound THEN
            ParkingSpaces[BestSpace] := TRUE;
            ParkingSpaceNumber := BestSpace;
        END_IF;
    END_IF;

    IF ExitGateSensor THEN
        IF ParkingSpaceNumber > 0 AND ParkingSpaces[ParkingSpaceNumber] THEN
            ParkingSpaces[ParkingSpaceNumber] := FALSE;
            ParkingSpaceNumber := 0;
        END_IF;
    END_IF;

    IF CarDetected AND RetrievalInProgress THEN
        IF MoveCarToExitGate(ParkingSpaceNumber) THEN
            ParkingSpaces[ParkingSpaceNumber] := FALSE;
            ParkingSpaceNumber := 0;
            RetrievalInProgress := FALSE;
        END_IF;
    END_IF;

    IF CarDetected AND NOT RetrievalInProgress THEN
        RetrievalInProgress := TRUE;
    END_IF;
