    BrewingStartTime : TIME;
    BrewingDuration : TIME;
END_VAR
VAR_OUTPUT
    HeatingElement : BOOL;
    AgitationMotor : BOOL;
    HopsDispenser : BOOL;
    FermentationTank : BOOL;
END_VAR
VAR
    CurrentTime : TIME;
    BrewingActive : BOOL;
    TimeElapsed : TIME;
    HopsDispensed : BOOL;
    TransferInitiated : BOOL;
END_VAR

CurrentTime := T#0s;
BrewingActive := FALSE;
TimeElapsed := T#0s;
HopsDispensed := FALSE;
TransferInitiated := FALSE;

IF (CurrentTime < BrewingStartTime) THEN
    CurrentTime := T#0s;
    BrewingActive := FALSE;
ELSIF (CurrentTime >= BrewingStartTime) AND (CurrentTime < (BrewingStartTime + BrewingDuration)) THEN
    BrewingActive := TRUE;
    TimeElapsed := CurrentTime - BrewingStartTime;

    HeatingElement := (TemperatureSensor < 65.0);
    AgitationMotor := (WaterFlowSensor > 0.5);

    IF (TimeElapsed >= T#5h) AND (NOT HopsDispensed) THEN
        HopsDispenser := TRUE;
        HopsDispensed := TRUE;
    END_IF;

    IF (TimeElapsed >= T#48h) AND (NOT TransferInitiated) THEN
        FermentationTank := TRUE;
        TransferInitiated := TRUE;
    END_IF;
ELSE
    HeatingElement := FALSE;
    AgitationMotor := FALSE;
    HopsDispenser := FALSE;
    FermentationTank := FALSE;
    CurrentTime := T#0s;
    TimeElapsed := T#0s;
    HopsDispensed := FALSE;
    TransferInitiated := FALSE;
END_IF;
