END_VAR
VAR
    IsLargeParcel : BOOL;
    IsSmallParcel : BOOL;
    IsValidSize : BOOL;
    IsValidDestination : BOOL;
    IsErrorCondition : BOOL;
END_VAR

    IsLargeParcel := ParcelSizeSensor >= 0.5;
    IsSmallParcel := ParcelSizeSensor < 0.5;
    IsValidSize := IsLargeParcel OR IsSmallParcel;
    IsValidDestination := (DestinationCodeSensor = 1) OR (DestinationCodeSensor = 2);
    IsErrorCondition := NOT IsValidSize OR NOT IsValidDestination;

    ConveyorBeltMotor := NOT IsErrorCondition;
    SortingGate1 := IsErrorCondition OR (IsLargeParcel AND IsValidDestination);
    SortingGate2 := IsErrorCondition OR (IsSmallParcel AND (DestinationCodeSensor = 1));
END_FUNCTION_BLOCK

